#include <array>
#include <cstddef>
#include <iostream>

template <typename T, std::size_t Rows, std::size_t Cols>
using Array2d = std::array<std::array<T, Cols>, Rows>;

int main()
{
    Array2d<int, 2, 3> input{};
    Array2d<int, 3, 2> result{};

    for (std::size_t r{ 0 }; r < input.size(); ++r)
        for (std::size_t c{ 0 }; c < input[0].size(); ++c)
            std::cin >> input[r][c];

    for (std::size_t r{ 0 }; r < input.size(); ++r)
        for (std::size_t c{ 0 }; c < input[0].size(); ++c)
            result[c][r] = input[r][c];

    for (std::size_t r{ 0 }; r < result.size(); ++r)
    {
        for (std::size_t c{ 0 }; c < result[0].size(); ++c)
        {
            if (c > 0)
                std::cout << ' ';
            std::cout << result[r][c];
        }
        std::cout << '\n';
    }

    return 0;
}
